// ============================================================
// VOICES INTERFACE IMPLEMENTATION
// ============================================================

impl VoicesGuest for TtsElevenlabsComponent {
    type Voice = voices::VoiceImpl;
    type VoiceResults = voices::VoiceResultsImpl;

    fn list_voices(
        filter: Option<wit_voices::VoiceFilter>,
    ) -> Result<wit_voices::VoiceResults, wit_types::TtsError> {
        return voices::list_voices(filter);
    }

    fn get_voice(voice_id: String) -> Result<wit_voices::Voice, wit_types::TtsError> {
        return voices::get_voice(voice_id);
    }

    fn search_voices(
        query: String,
        filter: Option<wit_voices::VoiceFilter>,
    ) -> Result<Vec<wit_voices::VoiceInfo>, wit_types::TtsError> {
        return voices::search_voices(query, filter);
    }

    fn list_languages() -> Result<Vec<wit_voices::LanguageInfo>, wit_types::TtsError> {
        return voices::list_languages();
    }
}

// ============================================================
// SYNTHESIS INTERFACE IMPLEMENTATION
// ============================================================

impl SynthesisGuest for TtsElevenlabsComponent {
    fn synthesize(
        input: wit_types::TextInput,
        voice: wit_voices::VoiceBorrow<'_>,
        options: Option<wit_synthesis::SynthesisOptions>,
    ) -> Result<wit_types::SynthesisResult, wit_types::TtsError> {
        return synthesis::synthesize(input, voice.get(), options);
    }

    fn synthesize_batch(
        inputs: Vec<wit_types::TextInput>,
        voice: wit_voices::VoiceBorrow<'_>,
        options: Option<wit_synthesis::SynthesisOptions>,
    ) -> Result<Vec<wit_types::SynthesisResult>, wit_types::TtsError> {
        return synthesis::synthesize_batch(inputs, voice.get(), options);
    }

    fn get_timing_marks(
        input: wit_types::TextInput,
        voice: wit_voices::VoiceBorrow<'_>,
    ) -> Result<Vec<wit_types::TimingInfo>, wit_types::TtsError> {
        return synthesis::get_timing_marks(input, voice.get());
    }

    fn validate_input(
        input: wit_types::TextInput,
        voice: wit_voices::VoiceBorrow<'_>,
    ) -> Result<wit_synthesis::ValidationResult, wit_types::TtsError> {
        return synthesis::validate_input(input, voice.get());
    }
}

// ============================================================
