// ============================================================
// ADVANCED INTERFACE IMPLEMENTATION
// ============================================================

impl AdvancedGuest for TtsElevenlabsComponent {
    type PronunciationLexicon = advanced::PronunciationLexiconImpl;
    type LongFormOperation = advanced::LongFormOperationImpl;

    fn create_voice_clone(
        name: String,
        audio_samples: Vec<wit_advanced::AudioSample>,
        description: Option<String>,
    ) -> Result<wit_voices::Voice, wit_types::TtsError> {
        return advanced::create_voice_clone(name, audio_samples, description);
    }

    fn design_voice(
        name: String,
        characteristics: wit_advanced::VoiceDesignParams,
    ) -> Result<wit_voices::Voice, wit_types::TtsError> {
        return advanced::design_voice(name, characteristics);
    }

    fn convert_voice(
        input_audio: Vec<u8>,
        target_voice: wit_voices::VoiceBorrow<'_>,
        preserve_timing: Option<bool>,
    ) -> Result<Vec<u8>, wit_types::TtsError> {
        return advanced::convert_voice(input_audio, target_voice.get(), preserve_timing);
    }

    fn generate_sound_effect(
        description: String,
        duration_seconds: Option<f32>,
        style_influence: Option<f32>,
    ) -> Result<Vec<u8>, wit_types::TtsError> {
        return advanced::generate_sound_effect(description, duration_seconds, style_influence);
    }

    fn create_lexicon(
        name: String,
        language: String,
        entries: Option<Vec<wit_advanced::PronunciationEntry>>,
    ) -> Result<wit_advanced::PronunciationLexicon, wit_types::TtsError> {
        return advanced::create_lexicon(name, language, entries);
    }

    fn synthesize_long_form(
        content: String,
        voice: wit_voices::VoiceBorrow<'_>,
        output_location: String,
        chapter_breaks: Option<Vec<u32>>,
    ) -> Result<wit_advanced::LongFormOperation, wit_types::TtsError> {
        return advanced::synthesize_long_form(
            content,
            voice.get(),
            output_location,
            chapter_breaks,
        );
    }
}

